template <typename T, int SIZE_X, int SIZE_Y, int BOUNDARY_X>
class TransformBuffer {
public:
    enum {
        VERTICAL_STRIDE = BOUNDARY_X + (SIZE_X / 2)
    };

private:
    enum {
        SHM_BANKS = 16,
        BUFFER_SIZE = VERTICAL_STRIDE * SIZE_Y,
        PADDING = SHM_BANKS - ((BUFFER_SIZE + SHM_BANKS / 2) % SHM_BANKS),
        ODD_OFFSET = BUFFER_SIZE + PADDING,
    };

    T data[2 * BUFFER_SIZE + PADDING];

    template <typename FUNC>
    void horizontalStep(int count, int prevOffset, int midOffset, int nextOffset, FUNC function) {
        int STEPS = count / SIZE_X;
        int finalCount = count % SIZE_X;
        int finalOffset = count - finalCount;

        for(int i = 0; i < STEPS; i++) {
            T previous = data[prevOffset + i * SIZE_X + get_local_id(0)];
            T next     = data[nextOffset + i * SIZE_X + get_local_id(0)];
            T center  = data[midOffset  + i * SIZE_X + get_local_id(0)];
            if (function.scale != 0.0f) {
                center += function.scale * (previous + next);
            } else {
                center -= (previous + next) / 2;
            }
            data[midOffset + i * SIZE_X + get_local_id(0)] = center;
        }

        if(get_local_id(0) < finalCount) {
            T previous = data[prevOffset + finalOffset + get_local_id(0)];
            T next     = data[nextOffset + finalOffset + get_local_id(0)];
            T center  = data[midOffset + finalOffset + get_local_id(0)];
            if (function.scale != 0.0f) {
                center += function.scale * (previous + next);
            } else {
                center -= (previous + next) / 2;
            }
            data[midOffset + finalOffset + get_local_id(0)] = center;
        }
    }

public:
    int getColumnOffset(int columnIndex) {
        columnIndex += BOUNDARY_X;
        return columnIndex / 2 + (columnIndex & 1) * ODD_OFFSET;
    }

    T & operator[](int index) {
        return data[index];
    }

    template <typename FUNC>
    void forEachHorizontalEven(int firstLine, int numLines, FUNC func) {
        int count = numLines * VERTICAL_STRIDE - 1;
        int centerOffset = firstLine * VERTICAL_STRIDE + 1;
        int prevOffset = firstLine * VERTICAL_STRIDE + ODD_OFFSET;
        int nextOffset = prevOffset + 1;
        horizontalStep(count, prevOffset, centerOffset, nextOffset, func);
    }

    template <typename FUNC>
    void forEachHorizontalOdd(int firstLine, int numLines, FUNC func) {
        int count = numLines * VERTICAL_STRIDE - 1;
        int prevOffset = firstLine * VERTICAL_STRIDE;
        int centerOffset = prevOffset + ODD_OFFSET;
        int nextOffset = prevOffset + 1;
        horizontalStep(count, prevOffset, centerOffset, nextOffset, func);
    }

    template <typename F>
    void forEachVerticalEven(int columnOffset, F f) {
        if(SIZE_Y > 3) {
            int steps = SIZE_Y / 2 - 1;
            for(int i = 0; i < steps; i++) {
                int row = 2 + i * 2;
                T prev = data[columnOffset + (row - 1) * VERTICAL_STRIDE];
                T next = data[columnOffset + (row + 1) * VERTICAL_STRIDE];
                T center = data[columnOffset + row * VERTICAL_STRIDE];
                if (f.scale != 0.0f) {
                    center += f.scale * (prev + next);
                } else {
                    center += (prev + next + 2) / 4;
                }
                data[columnOffset + row * VERTICAL_STRIDE] = center;
            }
        }
    }

    template <typename F>
    void forEachVerticalOdd(int columnOffset, F f) {
        int steps = (SIZE_Y - 1) / 2;
        for(int i = 0; i < steps; i++) {
            int row = i * 2 + 1;
            T prev = data[columnOffset + (row - 1) * VERTICAL_STRIDE];
            T next = data[columnOffset + (row + 1) * VERTICAL_STRIDE];
            T center = data[columnOffset + row * VERTICAL_STRIDE];
            if (f.scale != 0.0f) {
                center += f.scale * (prev + next);
            } else {
                center -= (prev + next) / 2;
            }
            data[columnOffset + row * VERTICAL_STRIDE] = center;
        }
    }

    void scaleHorizontal(T evenScale, T oddScale, int firstLine, int numLines) {
        int offset = firstLine * VERTICAL_STRIDE;
        int count = numLines * VERTICAL_STRIDE;
        int steps = count / SIZE_X;
        int finalCount = count % SIZE_X;
        int finalOffset = count - finalCount;

        for(int i = 0; i < steps; i++) {
            data[get_local_id(0) + i * SIZE_X + offset] *= evenScale;
            data[get_local_id(0) + i * SIZE_X + offset + ODD_OFFSET] *= oddScale;
        }

        if(get_local_id(0) < finalCount) {
            data[get_local_id(0) + finalOffset + offset] *= evenScale;
            data[get_local_id(0) + finalOffset + offset + ODD_OFFSET] *= oddScale;
        }
    }

    void scaleVertical(T evenScale, T oddScale, int columnOffset, int numLines, int firstLine) {
        for(int i = firstLine; i < (numLines + firstLine); i++) {
            if(i & 1) {
                data[columnOffset + i * VERTICAL_STRIDE] *= oddScale;
            } else {
                data[columnOffset + i * VERTICAL_STRIDE] *= evenScale;
            }
        }
    }
};

#endif

#ifndef IO_H
#define IO_H

class DWTIO {
protected:
    static void mirror(int &d, const int &sizeD) {
        if(d >= sizeD) {
            d = 2 * sizeD - 2 - d;
        } else if(d < 0) {
            d = -d;
        }
    }
};

template <typename T, bool CHECKED>
class VerticalDWTPixelIO : protected DWTIO {
protected:
    int end;
    int stride;

    int initialize(int sizeX, int sizeY, int firstX, int firstY) {
        end = CHECKED ? (sizeY * sizeX + firstX) : 0;
        stride = sizeX;
        return firstX + sizeX * firstY;
    }
};

template <typename T, bool CHECKED>
class VerticalDWTPixelWriter : VerticalDWTPixelIO<T, CHECKED> {
private:
    int next;

public:
    void init(int sizeX, int sizeY, int firstX, int firstY) {
        if(firstX < sizeX) {
            next = this->initialize(sizeX, sizeY, firstX, firstY);
        } else {
            this->end = 0;
            this->stride = 0;
            next = 0;
        }
    }

    void writeInto(T *output, const T &value) {
        if((!CHECKED) || (next != this->end)) {
            output[next] = value;
            next += this->stride;
        }
    }
};

template <typename T, bool CHECKED>
class VerticalDWTPixelLoader : protected VerticalDWTPixelIO<const T, CHECKED> {
private:
    int last;

public:
    void init(int sizeX, int sizeY, int firstX, int firstY) {
        this->mirror(firstX, sizeX);
        last = this->initialize(sizeX, sizeY, firstX, firstY) - sizeX;
    }

    void clear() {
        this->end = 0;
        this->stride = 0;
        this->last = 0;
    }

    T loadFrom(const T *input) {
        last += this->stride;
        if(CHECKED && (last == this->end)) {
            last -= 2 * this->stride;
            this->stride = -this->stride;
        }
        return input[last];
    }
};

template <typename T, bool CHECKED>
class VerticalDWTBandIO : protected DWTIO {
protected:
    int end;
    int strideHighToLow;
    int strideLowToHigh;

    int initialize(int imageSizeX, int imageSizeY, int firstX, int firstY) {
        int columnOffset = firstX / 2;
        int verticalStride;

        if(firstX & 1) {
            verticalStride = imageSizeX / 2;
            columnOffset += ((imageSizeX + 1) / 2) * ((imageSizeY + 1) / 2);
            strideLowToHigh = (imageSizeX * imageSizeY) / 2;
        } else {
            verticalStride = imageSizeX / 2 + (imageSizeX & 1);
            strideLowToHigh = ((imageSizeY + 1) / 2) * imageSizeX;
        }

        strideHighToLow = verticalStride - strideLowToHigh;

        if(CHECKED) {
            end = columnOffset + (imageSizeY / 2) * verticalStride + (imageSizeY & 1) * strideLowToHigh;
        } else {
            end = 0;
        }

        return columnOffset + (firstY / 2) * verticalStride + (firstY & 1) * strideLowToHigh;
    }
};

template <typename T, bool CHECKED>
class VerticalDWTBandLoader : public VerticalDWTBandIO<const T, CHECKED> {
private:
    int last;

    T updateAndLoad(const T *input, const int &stride) {
        last += stride;
        if(CHECKED && (last == this->end)) {
            last -= (this->strideLowToHigh + this->strideHighToLow);
            int temp = this->strideLowToHigh;
            this->strideLowToHigh = -this->strideHighToLow;
            this->strideHighToLow = -temp;
        }
        return input[last];
    }

public:
    void init(int imageSizeX, int imageSizeY, int firstX, int firstY) {
        this->mirror(firstX, imageSizeX);
        last = this->initialize(imageSizeX, imageSizeY, firstX, firstY);
        last -= (firstY & 1) ? this->strideLowToHigh : this->strideHighToLow;
    }

    void clear() {
        this->end = 0;
        this->strideHighToLow = 0;
        this->strideLowToHigh = 0;
        this->last = 0;
    }

    T loadLowFrom(const T *input) {
        return updateAndLoad(input, this->strideHighToLow);
    }

    T loadHighFrom(const T *input) {
        return updateAndLoad(input, this->strideLowToHigh);
    }
};

template <typename T, bool CHECKED>
class VerticalDWTBandWriter : public VerticalDWTBandIO<T, CHECKED> {
private:
    int next;

    int saveAndUpdate(T *output, const T &item, const int &stride) {
        if((!CHECKED) || (next != this->end)) {
            output[next] = item;
            next += stride;
        }
        return next;
    }

public:
    void init(int imageSizeX, int imageSizeY, int firstX, int firstY) {
        if (firstX < imageSizeX) {
            next = this->initialize(imageSizeX, imageSizeY, firstX, firstY);
        } else {
            clear();
        }
    }

    void clear() {
        this->end = 0;
        this->strideHighToLow = 0;
        this->strideLowToHigh = 0;
        this->next = 0;
    }

    int writeLowInto(T *output, const T &primary) {
        return saveAndUpdate(output, primary, this->strideLowToHigh);
    }

    int writeHighInto(T *output, const T &other) {
        return saveAndUpdate(output, other, this->strideHighToLow);
    }
};

